func_ret_t create_matrix(float **mp, int size){
    float *m;
    int i,j;
    float lamda = -0.001f;
    float *coe;
    float coe_i =0.0f;

    coe = (float*)malloc(sizeof(float) * (2*size-1));
    if (coe == NULL)
        return RET_FAILURE;

    for (i=0; i < size; i++)
    {
        coe_i = 10 * exp(lamda*i);
        j=size-1+i;
        coe[j]=coe_i;
        j=size-1-i;
        coe[j]=coe_i;
    }

    m = (float*) malloc(sizeof(float)*size*size);
    if ( m == NULL) {
        free(coe);
        return RET_FAILURE;
    }

    for (i=0; i < size; i++) {
        for (j=0; j < size; j++) {
            m[i*size+j]=coe[size-1-i+j];
        }
    }

    free(coe);
    *mp = m;

    return RET_SUCCESS;
}

