#ifdef TIMING
static void tvsub(const struct timeval *t1, const struct timeval *t2, struct timeval *tr)
{
    tr->tv_sec = t1->tv_sec - t2->tv_sec;
    tr->tv_usec = t1->tv_usec - t2->tv_usec;
    if (tr->tv_usec < 0) {
        --tr->tv_sec;
        tr->tv_usec += 1000000;
    }
}

static float event_elapsed_ms(cudaEvent_t start, cudaEvent_t stop)
{
    float ms = 0.0f;
    cudaEventSynchronize(stop);
    cudaEventElapsedTime(&ms, start, stop);
    return ms;
}
#endif

static int initialize(int platform_id_inuse, int device_id_inuse)
{
    int num_devices = 0;
    (void)platform_id_inuse;

    cudaError_t cerr = cudaGetDeviceCount(&num_devices);
    if (cerr != cudaSuccess) {
        printf("ERROR: clGetDeviceIDs failed\n");
        return -1;
    }

    printf("num_devices = %d\n", num_devices);

    if (device_id_inuse > num_devices) {
        printf("Invalid Device Number\n");
        return -1;
    }

    if (num_devices <= 0) {
        printf("ERROR: clGetDeviceIDs failed\n");
        return -1;
    }

    if (device_id_inuse >= num_devices)
        device_id_inuse = num_devices - 1;

    cerr = cudaSetDevice(device_id_inuse);
    if (cerr != cudaSuccess) {
        printf("ERROR: clCreateContextFromType(GPU) failed\n");
        return -1;
    }

    printf("Create GPU context\n");
    return 0;
}

